ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?demographic_group ?professional_field ?name ?publisher WHERE {
  ?d a :Demographics .
  ?m a :Magazines .
  ?d p:hasMagazines ?m .
  ?d p:demographic_group ?demographic_group .
  ?d p:professional_field ?professional_field .
  ?m p:name ?name .
  ?m p:publisher ?publisher .
} }
  component: { SELECT ?demographic_group ?name ?publisher WHERE {
  ?d a :Demographics .
  ?m a :Magazines .
  ?d p:hasMagazines ?m .
  ?d p:demographic_group ?demographic_group .
  ?m p:name ?name .
  ?m p:publisher ?publisher .
} }
  component_2: { SELECT ?professional_field ?name ?publisher WHERE {
  ?d a :Demographics .
  ?m a :Magazines .
  ?d p:hasMagazines ?m .
  ?d p:professional_field ?professional_field .
  ?m p:name ?name .
  ?m p:publisher ?publisher .
} }
}

PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?professional_field_g (COUNT(*) AS ?agg) WHERE {
  ?demographics a :Demographics .
  ?demographics p:professional_field ?professional_field_g .
}
GROUP BY ?professional_field_g }
  component_2: { SELECT ?demographic_group_g (COUNT(*) AS ?agg) WHERE {
  ?demographics a :Demographics .
  ?demographics p:demographic_group ?demographic_group_g .
}
GROUP BY ?demographic_group_g }
  full: { SELECT ?demographic_group_g ?professional_field_g (COUNT(*) AS ?agg) WHERE {
  ?demographics a :Demographics .
  ?demographics p:demographic_group ?demographic_group_g .
  ?demographics p:professional_field ?professional_field_g .
}
GROUP BY ?demographic_group_g ?professional_field_g }
}
